import React, { useEffect } from "react";
import Aos from "aos";
import { Link } from "react-router-dom";
import "aos/dist/aos.css";
import "./Main.css";

function Main({ images, onImageLoad }) {
  if (!images || images.length === 0) {
    return <div>No products available</div>;
  }

  return (
    <section className="BG" dir="rtl">
      <section id="main" className="main container section">
        <div className="secTitle">
          <h3 data-aos="fade-right" data-aos-duration="1200" className="title">
            ألق نظرة على منتجاتنا :
          </h3>
        </div>
        <div className="secContent grid">
          {images.map((product, index) => (
            <Link key={index} to={`/Product/${index}`}>
              <div
                data-aos="fade-up"
                data-aos-duration="1200"
                className="singleProduct"
              >
                <div className="imageDiv">
                  <img
                    src={product.Images[0]}
                    alt={product.title}
                    loading="lazy"
                    onLoad={onImageLoad} // Call onImageLoad
                  />
                </div>
                <div className="cardInfo">
                  <h4 className="productTitle">{product.title}</h4>
                  <div className="desc">
                    <p>{product.description}</p>
                  </div>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </section>
    </section>
  );
}

export default Main;




